// n8n Code node - DBH EHR Chatbot v7.0 (Fixed)
const body = $input.item.json;
const token = (body.body && body.body.token) || body.token || '';
const rawMsg = ((body.body && body.body.message) || body.message || '').trim();
const GATEWAY = 'http://gateway:5000';
const AI_KEY = $env.OPENROUTER_API_KEY || '';

if (!token) {
  return [{ json: { type: 'text', message: 'Vui lòng đăng nhập để sử dụng tính năng này.' } }];
}

// Helpers
async function httpGet(url) {
  return await this.helpers.httpRequest({
    method: 'GET', url,
    headers: { Authorization: 'Bearer ' + token },
    json: true
  });
}

async function httpPost(url, payload) {
  return await this.helpers.httpRequest({
    method: 'POST', url,
    headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json' },
    body: payload, json: true
  });
}

async function httpSafe(method, url, payload) {
  try {
    return await this.helpers.httpRequest({
      method, url,
      headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json' },
      body: payload || undefined,
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
  } catch(e) {
    let errBody = null;
    try { errBody = e.response?.body || e.response?.data || null; } catch(_) {}
    return { statusCode: 400, body: errBody || { message: e.message } };
  }
}

function extractErrMsg(payload) {
  if (!payload) return 'Lỗi không xác định';
  if (typeof payload === 'string') { try { payload = JSON.parse(payload); } catch(_) { return payload; } }
  return payload.message || payload.Message || payload.title ||
         Object.values(payload.errors || {})?.[0]?.[0] || JSON.stringify(payload);
}

function fmtStatus(s) {
  const map = { PENDING:'Chờ duyệt', CONFIRMED:'Đã xác nhận', CHECKED_IN:'Đã đến',
    IN_PROGRESS:'Đang khám', COMPLETED:'Hoàn thành', CANCELLED:'Đã hủy',
    NO_SHOW:'Vắng mặt', RESCHEDULED:'Dời lịch' };
  return map[s] || s;
}

function fmtDateTime(iso) {
  const d = new Date(iso);
  const pad = n => String(n).padStart(2,'0');
  return pad(d.getDate()) + '/' + pad(d.getMonth()+1) + '/' + d.getFullYear() +
         ' ' + pad(d.getHours()) + ':' + pad(d.getMinutes());
}

// ACTION commands
if (rawMsg.startsWith('ACTION:')) {
  const parts = rawMsg.split('|');
  const cmd = parts[0];

  // BOOKING: Chọn bác sĩ -> Chọn ngày
  if (cmd.startsWith('ACTION:BOOK_DOCTOR_ID:')) {
    const doctorId = cmd.replace('ACTION:BOOK_DOCTOR_ID:', '');
    const doctorName = decodeURIComponent((parts[1] || '').replace('NAME:', ''));
    const orgId = (parts[2] || '').replace('ORG:', '');

    const dates = [];
    const today = new Date();
    for (let i = 1; i <= 6; i++) {
      const d = new Date(today);
      d.setDate(today.getDate() + i);
      const label = d.toLocaleDateString('vi-VN', { weekday: 'short', day: '2-digit', month: '2-digit' });
      const yy = d.getFullYear(), mm = String(d.getMonth()+1).padStart(2,'0'), dd = String(d.getDate()).padStart(2,'0');
      const value = yy + '-' + mm + '-' + dd;
      dates.push({
        id: value,
        label: label,
        sublabel: value,
        payload: `ACTION:SELECT_DATE:${value}|DOC:${doctorId}|NAME:${encodeURIComponent(doctorName)}|ORG:${orgId}`
      });
    }
    return [{ json: { type: 'date_selection', message: `Chọn ngày khám với ${doctorName}:`, data: dates } }];
  }

  // BOOKING: Chọn ngày -> Chọn giờ
  if (cmd.startsWith('ACTION:SELECT_DATE:')) {
    const date = cmd.replace('ACTION:SELECT_DATE:', '');
    const doctorId = (parts[1] || '').replace('DOC:', '');
    const doctorName = decodeURIComponent((parts[2] || '').replace('NAME:', ''));
    const orgId = (parts[3] || '').replace('ORG:', '');

    const slots = ['08:00', '08:30', '09:00', '09:30', '10:00', '14:00', '14:30', '15:00', '15:30', '16:00'];
    const timeData = slots.map(s => ({
      id: s,
      label: s,
      payload: `ACTION:PREVIEW_BOOKING:${date}T${s}:00|DOC:${doctorId}|NAME:${encodeURIComponent(doctorName)}|ORG:${orgId}`
    }));
    return [{ json: { type: 'time_selection', message: `Ngày ${date} - Chọn giờ khám với ${doctorName}:`, data: timeData } }];
  }

  // BOOKING: Preview xác nhận
  if (cmd.startsWith('ACTION:PREVIEW_BOOKING:')) {
    const scheduledRaw = cmd.replace('ACTION:PREVIEW_BOOKING:', '');
    const doctorId = (parts[1] || '').replace('DOC:', '');
    const doctorName = decodeURIComponent((parts[2] || '').replace('NAME:', ''));
    const orgId = (parts[3] || '').replace('ORG:', '');
    const datePart = scheduledRaw.split('T')[0];
    const timePart = scheduledRaw.split('T')[1]?.substring(0, 5);

    const previewData = [
      { id: 'confirm', label: 'Xác nhận', payload: `ACTION:EXECUTE_BOOKING:${scheduledRaw}|DOC:${doctorId}|NAME:${encodeURIComponent(doctorName)}|ORG:${orgId}` },
      { id: 'cancel', label: 'Hủy bỏ', payload: 'Hủy đặt lịch' }
    ];

    return [{ json: {
      type: 'confirmation',
      message: `XÁC NHẬN ĐẶT LỊCH\n\nNgày: ${datePart}\nGiờ: ${timePart}\nBác sĩ: ${doctorName}\n\nBạn xác nhận đặt lịch?`,
      data: previewData
    } }];
  }

  // BOOKING: Thực thi đặt lịch
  if (cmd.startsWith('ACTION:EXECUTE_BOOKING:')) {
    const scheduledRaw = cmd.replace('ACTION:EXECUTE_BOOKING:', '');
    const dateTime = scheduledRaw.includes('T') ? (scheduledRaw.length === 16 ? scheduledRaw + ':00' : scheduledRaw) : scheduledRaw;

    let doctorId = '';
    let orgId = '';
    for (let i = 1; i < parts.length; i++) {
      if (parts[i].startsWith('DOC:')) {
        doctorId = parts[i].replace('DOC:', '');
      } else if (parts[i].startsWith('ORG:')) {
        orgId = parts[i].replace('ORG:', '');
      }
    }

    let patientId = '';
    try {
      const pd = await httpGet(GATEWAY + '/api/v1/auth/me');
      const p = pd.profiles || pd.Profiles || {};
      const pt = p.Patient || p.patient || {};
      patientId = pt.patientId || pt.PatientId || '';
    } catch(e) {
      return [{ json: { type: 'text', message: 'Lỗi lấy hồ sơ: ' + e.message } }];
    }

    if (!patientId) {
      return [{ json: { type: 'text', message: 'Tài khoản chưa có hồ sơ Bệnh nhân.' } }];
    }

    const res = await httpSafe('POST', GATEWAY + '/api/v1/Appointments', {
      patientId,
      doctorId,
      orgId,
      scheduledAt: dateTime
    });

    if (res.statusCode === 200 || res.statusCode === 201) {
      return [{ json: { type: 'text', message: 'Đặt lịch thành công!' } }];
    } else {
      return [{ json: { type: 'text', message: 'Lỗi: ' + extractErrMsg(res.body) } }];
    }
  }

  // VIEW APPOINTMENTS
  if (cmd === 'ACTION:VIEW_APPOINTMENTS') {
    let patientId = '';
    try {
      const pd = await httpGet(GATEWAY + '/api/v1/auth/me');
      const p = pd.profiles || pd.Profiles || {};
      const pt = p.Patient || p.patient || {};
      patientId = pt.patientId || pt.PatientId || '';
    } catch(e) {
      return [{ json: { type: 'text', message: 'Lỗi lấy hồ sơ: ' + e.message } }];
    }

    if (!patientId) {
      return [{ json: { type: 'text', message: 'Tài khoản chưa có hồ sơ Bệnh nhân.' } }];
    }

    const res = await httpSafe('GET', GATEWAY + '/api/v1/Appointments?patientId=' + patientId + '&page=1&pageSize=8');
    if (res.statusCode !== 200) {
      return [{ json: { type: 'text', message: 'Lỗi: ' + extractErrMsg(res.body) } }];
    }

    const appts = (res.body.data || res.body.Data || []).filter(a => a.status !== 'CANCELLED' && a.status !== 'COMPLETED');
    if (appts.length === 0) {
      return [{ json: { type: 'text', message: 'Bạn không có lịch hẹn nào đang hoạt động.' } }];
    }

    const items = appts.map(a => ({
      id: a.appointmentId,
      label: fmtDateTime(a.scheduledAt),
      sublabel: fmtStatus(a.status),
      payload: 'ACTION:APPT_DETAIL:' + a.appointmentId
    }));
    return [{ json: { type: 'appointment_list', message: 'Lịch hẹn của bạn (chọn để xem chi tiết):', data: items } }];
  }

  // APPOINTMENT DETAIL
  if (cmd.startsWith('ACTION:APPT_DETAIL:')) {
    const apptId = cmd.replace('ACTION:APPT_DETAIL:', '');
    const res = await httpSafe('GET', GATEWAY + '/api/v1/Appointments/' + apptId);
    if (res.statusCode !== 200) {
      return [{ json: { type: 'text', message: 'Lỗi: ' + extractErrMsg(res.body) } }];
    }

    const a = res.body.data || res.body;
    const canCancel = ['PENDING', 'CONFIRMED'].includes(a.status);
    const info = `THÔNG TIN LỊCH HẸN\n\nThời gian: ${fmtDateTime(a.scheduledAt)}\nTrạng thái: ${fmtStatus(a.status)}\nMã số: ${a.appointmentId.slice(-8).toUpperCase()}`;

    if (!canCancel) {
      return [{ json: { type: 'text', message: info + '\n\n(Lịch này không thể hủy)' } }];
    }

    const actions = [
      { id: 'cancel', label: 'Hủy lịch này', payload: 'ACTION:CONFIRM_CANCEL:' + apptId },
      { id: 'back', label: 'Quay lại', payload: 'ACTION:VIEW_APPOINTMENTS' }
    ];
    return [{ json: { type: 'confirmation', message: info, data: actions } }];
  }

  // CONFIRM CANCEL
  if (cmd.startsWith('ACTION:CONFIRM_CANCEL:')) {
    const apptId = cmd.replace('ACTION:CONFIRM_CANCEL:', '');
    const actions = [
      { id: 'yes', label: 'Xác nhận hủy', payload: 'ACTION:EXECUTE_CANCEL:' + apptId },
      { id: 'no', label: 'Không hủy', payload: 'ACTION:VIEW_APPOINTMENTS' }
    ];
    return [{ json: {
      type: 'confirmation',
      message: `XÁC NHẬN HỦY LỊCH\n\nBạn có chắc muốn hủy lịch hẹn này?\nLý do: Bệnh nhân yêu cầu hủy.`,
      data: actions
    } }];
  }

  // EXECUTE CANCEL
  if (cmd.startsWith('ACTION:EXECUTE_CANCEL:')) {
    const apptId = cmd.replace('ACTION:EXECUTE_CANCEL:', '');
    const res = await httpSafe('PUT', GATEWAY + '/api/v1/Appointments/' + apptId + '/cancel', {
      reason: 'Bệnh nhân yêu cầu hủy qua chatbot'
    });
    if (res.statusCode === 200 || res.statusCode === 201) {
      return [{ json: { type: 'text', message: 'Đã hủy lịch hẹn thành công.' } }];
    } else {
      return [{ json: { type: 'text', message: 'Lỗi: ' + extractErrMsg(res.body) } }];
    }
  }

  return [{ json: { type: 'text', message: 'Lệnh không nhận dạng được.' } }];
}

// Classify with AI
let intent = 'GREETING';
let greetingResponse = 'Xin chào! Tôi có thể giúp bạn đặt lịch khám, xem lịch hẹn hoặc tra cứu bệnh án.';
let extractedSpecialty = null;

try {
  const aiRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://openrouter.ai/api/v1/chat/completions',
    headers: { Authorization: 'Bearer ' + AI_KEY, 'Content-Type': 'application/json', 'HTTP-Referer': 'https://dbh-ehr.local' },
    body: {
      model: 'openai/gpt-4o-mini',
      response_format: { type: 'json_object' },
      temperature: 0.1,
      messages: [
        { role: 'system', content: `Phân loại ý định người dùng. Trả về JSON.

Các intent:
- BOOK_APPOINTMENT: đặt lịch khám, tìm bác sĩ
- VIEW_APPOINTMENTS: xem lịch hẹn
- EHR_QUERY: xem hồ sơ bệnh án
- POLICY_QUERY: hỏi chính sách
- GREETING: chào hỏi

Ví dụ:
- "Tìm bác sĩ Nhi khoa" -> {"intent":"BOOK_APPOINTMENT","specialty":"nhi khoa"}
- "Xem lịch hẹn" -> {"intent":"VIEW_APPOINTMENTS"}
- "Xem hồ sơ" -> {"intent":"EHR_QUERY"}
- "Chào bạn" -> {"intent":"GREETING","response":"Xin chào!"}` },
        { role: 'user', content: rawMsg }
      ]
    },
    json: true
  });

  const aiText = aiRes?.choices?.[0]?.message?.content || '{}';
  let parsed = {};
  try { const m = aiText.match(/{[\s\S]*}/); if (m) parsed = JSON.parse(m[0]); } catch(e) {}

  intent = parsed.intent || 'GREETING';
  greetingResponse = parsed.response || 'Xin chào! Tôi có thể giúp gì cho bạn?';
  extractedSpecialty = parsed.specialty || null;
} catch(e) {
  return [{ json: { type: 'text', message: 'Lỗi kết nối AI: ' + e.message } }];
}

// Route by intent
if (intent === 'GREETING') {
  return [{ json: { type: 'text', message: greetingResponse } }];
}

if (intent === 'POLICY_QUERY') {
  let userRole = 'patient';
  try { 
    const pd = await httpGet(GATEWAY + '/api/v1/auth/me'); 
    const rolesArray = pd.roles || pd.Roles || [];
    if (Array.isArray(rolesArray) && rolesArray.length > 0) {
      const adminStr = rolesArray.find(r => String(r).toLowerCase() === 'admin');
      userRole = adminStr ? 'admin' : String(rolesArray[0]).toLowerCase();
    }
  } catch(_) {}

  try {
    const ragRes = await this.helpers.httpRequest({
      method: 'POST', url: 'http://lightrag:9621/query',
      body: { query: rawMsg, mode: 'naive', namespace: userRole },
      json: true
    });
    const answer = ragRes.answer || ragRes.response || 'Không tìm thấy thông tin phù hợp.';
    return [{ json: { type: 'text', message: answer } }];
  } catch(e) {
    return [{ json: { type: 'text', message: 'Lỗi hệ thống: ' + e.message } }];
  }
}

if (intent === 'VIEW_APPOINTMENTS') {
  return [{ json: { type: 'action', message: 'Đang lấy danh sách lịch hẹn...', payload: 'ACTION:VIEW_APPOINTMENTS' } }];
}

if (intent === 'BOOK_APPOINTMENT') {
  const spec = (extractedSpecialty || 'nội khoa').toLowerCase().normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '').replace(/đ/g, 'd').trim();

  try {
    const searchData = await httpPost(GATEWAY + '/api/v1/memberships/doctors/search', {
      specialty: spec,
      page: 1,
      pageSize: 10
    });

    const rawData = searchData.data || searchData.Data || [];
    if (rawData.length === 0) {
      return [{ json: { type: 'text', message: 'Không tìm thấy bác sĩ chuyên khoa ' + (extractedSpecialty || 'nội khoa') } }];
    }

    const docs = rawData.map(d => {
      const user = d.user || d.User || {};
      const up = user.userProfile || user.UserProfile || {};
      const p = up.profiles || up.Profiles || {};
      const doc = p.Doctor || p.doctor || {};
      return {
        doctorId: doc.doctorId || d.membershipId || '',
        name: user.fullName || up.fullName || 'Bác sĩ',
        specialty: d.specialty || spec,
        orgName: d.orgName || 'Bệnh viện',
        orgId: String(d.orgId || d.OrgId || '')
      };
    }).filter(d => d.doctorId);

    if (docs.length === 0) {
      return [{ json: { type: 'text', message: 'Không tìm thấy thông tin bác sĩ chi tiết.' } }];
    }

    // Thêm payload cho mỗi bác sĩ
    const docsWithPayload = docs.map(doc => ({
      ...doc,
      payload: `ACTION:BOOK_DOCTOR_ID:${doc.doctorId}|NAME:${encodeURIComponent(doc.name)}|ORG:${doc.orgId}`
    }));

    return [{ json: { type: 'doctor_list', data: docsWithPayload } }];
  } catch(e) {
    return [{ json: { type: 'text', message: 'Lỗi tìm bác sĩ: ' + e.message } }];
  }
}

if (intent === 'EHR_QUERY') {
  try {
    const profileData = await httpGet(GATEWAY + '/api/v1/auth/me');
    const p = profileData.profiles || profileData.Profiles || {};
    const patient = p.Patient || p.patient || {};
    const pId = patient.patientId || patient.PatientId || profileData.userId || profileData.UserId || '';

    if (!pId) {
      return [{ json: { type: 'text', message: 'Cần đăng nhập bệnh nhân để xem hồ sơ.' } }];
    }

    const ehrData = await httpGet(GATEWAY + '/api/v1/ehr/records/patient/' + pId);
    const records = Array.isArray(ehrData) ? ehrData : (ehrData.data || ehrData.Data || []);
    const count = Array.isArray(records) ? records.length : 0;

    if (count === 0) {
      return [{ json: { type: 'text', message: 'Bạn chưa có hồ sơ bệnh án nào.' } }];
    }

    const orgCache = {};
    const items = await Promise.all(records.map(async r => {
      const ehrId = r.ehrId || r.EhrId || r.id || r.Id || '';
      const createdAt = r.createdAt || r.CreatedAt || r.date || r.Date || '';
      const diagnosis = r.diagnosis || r.Diagnosis || r.chiefComplaint || r.ChiefComplaint || 'Khám tổng quát';

      let orgNameStr = 'Không rõ';
      const oId = r.orgId || r.OrgId;
      if (oId) {
        if (!orgCache[oId]) {
          try {
            const orgRes = await httpSafe('GET', GATEWAY + '/api/v1/Organizations/' + oId);
            if (orgRes.statusCode === 200) {
              const oData = orgRes.body.data || orgRes.body;
              orgCache[oId] = oData.orgName || oData.name || oId;
            } else {
              orgCache[oId] = oId;
            }
          } catch (e) {
            orgCache[oId] = oId;
          }
        }
        orgNameStr = orgCache[oId];
      }

      const doctorName = r.doctorName || r.DoctorName || (r.doctor && (r.doctor.fullName || r.doctor.name)) || (oId ? 'Cơ sở ' + orgNameStr : 'Bác sĩ');
      const dateLabel = createdAt ? fmtDateTime(createdAt) : 'Không rõ ngày';
      return { ehrId, dateLabel, diagnosis, doctorName };
    }));
    return [{ json: { type: 'ehr_list', patientName: patient.fullName || 'Bệnh nhân', count, data: items } }];
  } catch(e) {
    return [{ json: { type: 'text', message: 'Lỗi tra cứu: ' + e.message } }];
  }
}

return [{ json: { type: 'text', message: 'Tôi chưa hiểu yêu cầu này.\n\nBạn có thể:\n- Đặt lịch khám (VD: "Tìm bác sĩ Nhi khoa")\n- Xem lịch hẹn (VD: "Xem lịch hẹn của tôi")\n- Tra cứu bệnh án (VD: "Xem hồ sơ bệnh án")' } }];
